// // This module generates a Johnson sequence on the falling edge of the clock signal and resets to the final value when the reset signal is low.
module johnson_counter_2bit(CLK, RESET, COUNT);
input CLK;
input RESET;
output reg [1:0] COUNT;

always @(posedge CLK or posedge RESET) begin
    if (RESET) begin
        COUNT <= 2'b00;
    end else begin
        COUNT <= {~COUNT[0], COUNT[1]};
    end
end

endmodule
